class Solution:
    def countPairsOfConnectableServers(self, edges, signalSpeed):
        from collections import defaultdict
        n = len(edges) + 1
        graph = defaultdict(list)
        for u, v, w in edges:
            graph[u].append((v, w))
            graph[v].append((u, w))
        def dfs(node, parent, dist):
            count = 1 if dist % signalSpeed == 0 else 0
            for nb, w in graph[node]:
                if nb != parent:
                    count += dfs(nb, node, dist + w)
            return count
        result = [0] * n
        for c in range(n):
            total = 0
            for nb, w in graph[c]:
                cnt = dfs(nb, c, w)
                result[c] += cnt * total
                total += cnt
        return result

