var countPairsOfConnectableServers = function(edges, signalSpeed) {
    const n = edges.length + 1;
    const graph = Array.from({length: n}, () => []);
    for (const [u, v, w] of edges) {
        graph[u].push([v, w]);
        graph[v].push([u, w]);
    }
    function dfs(node, parent, dist) {
        let count = dist % signalSpeed === 0 ? 1 : 0;
        for (const [nb, w] of graph[node]) {
            if (nb !== parent) count += dfs(nb, node, dist + w);
        }
        return count;
    }
    const result = new Array(n).fill(0);
    for (let c = 0; c < n; c++) {
        let total = 0;
        for (const [nb, w] of graph[c]) {
            const cnt = dfs(nb, c, w);
            result[c] += cnt * total;
            total += cnt;
        }
    }
    return result;
};
